/* =========
   Design System
   ========= */
:root {
    /* Primary brand */
    --color-primary-dark: #111111;
    --color-primary-darker: #000000;
    --color-accent: #D6453A;

    /* Secondary / neutrals */
    --color-secondary-700: #444444;
    --color-secondary-600: #666666;
    --color-neutral-900: #333333;
    --color-neutral-100: #F8F8F8;
    --color-neutral-0: #FFFFFF;

    /* Semantic */
    --color-success: #2E7D32;
    --color-error: #C62828;
    --color-warning: #ED6C02;
    --color-info: #1565C0;

    /* Typography */
    --font-heading: "Libre Franklin", Helvetica, Arial, sans-serif;
    --font-body: "Source Sans 3", -apple-system, BlinkMacSystemFont, "Segoe UI", Helvetica, Arial, sans-serif;
    --font-script: "Great Vibes", "Brush Script MT", cursive;

    --font-size-h1: 28px;
    --font-size-h2: 24px;
    --font-size-h3: 20px;
    --font-size-body: 14px;
    --font-size-small: 12px;

    --font-weight-light: 300;
    --font-weight-regular: 400;
    --font-weight-medium: 500;
    --font-weight-semibold: 600;
    --font-weight-bold: 700;

    --line-height-tight: 1.25;
    --line-height-normal: 1.5;
    --line-height-relaxed: 1.75;

    /* Spacing scale (4px base) */
    --space-xxs: 4px;
    --space-xs: 8px;
    --space-sm: 16px;
    --space-md: 24px;
    --space-lg: 32px;
    --space-xl: 48px;
    --space-xxl: 64px;

    --header-height-top: 32px;
    --header-height-main: 72px;

    --shadow-subtle: 0 1px 2px rgba(0, 0, 0, 0.15);
}

/* =========
   Global Reset & Base
   ========= */
*, *::before, *::after {
    box-sizing: border-box;
}

html {
    font-size: 100%;
}

body {
    margin: 0;
    padding: 0;
    font-family: var(--font-body);
    font-size: var(--font-size-body);
    line-height: var(--line-height-normal);
    color: var(--color-neutral-900);
    background-color: var(--color-neutral-100);
}

img {
    max-width: 100%;
    height: auto;
}

a {
    color: var(--color-accent);
    text-decoration: none;
}

a:hover,
a:focus {
    text-decoration: underline;
}

.page {
    min-height: 100vh;
    display: flex;
    flex-direction: column;
}

.container {
    width: 100%;
    max-width: 1140px;
    margin: 0 auto;
    padding-left: var(--space-sm);
    padding-right: var(--space-sm);
}

.visually-hidden {
    position: absolute;
    width: 1px;
    height: 1px;
    padding: 0;
    margin: -1px;
    overflow: hidden;
    clip: rect(0, 0, 0, 0);
    white-space: nowrap;
    border: 0;
}

/* =========
   Header
   ========= */
.site-header {
    background-color: var(--color-primary-dark);
    color: var(--color-neutral-0);
    box-shadow: var(--shadow-subtle);
}

/* Top contact bar */
.top-bar {
    height: var(--header-height-top);
    background-color: var(--color-primary-darker);
    color: var(--color-neutral-0);
    font-size: var(--font-size-small);
}

.top-bar-inner {
    height: 100%;
    display: flex;
    align-items: center;
    justify-content: space-between;
}

.top-bar-left {
    display: flex;
    align-items: center;
    gap: var(--space-xs);
}

.top-bar-icon {
    font-size: 14px;
}

.top-bar-text {
    letter-spacing: 0.03em;
}

.top-bar-right {
    color: #e0e0e0;
}

.top-bar-label {
    letter-spacing: 0.03em;
}

/* Main header bar */
.main-header {
    background-color: var(--color-primary-dark);
    border-top: 1px solid #1b1b1b;
    border-bottom: 1px solid #1b1b1b;
}

.header-inner {
    height: var(--header-height-main);
    display: flex;
    align-items: center;
    justify-content: space-between;
    gap: var(--space-md);
}

/* Branding (logo + wordmark) */
.branding {
    display: flex;
    align-items: center;
    gap: var(--space-sm);
}

.logo-mark {
    width: 56px;
    height: 56px;
    border-radius: 50%;
    border: 2px solid #dddddd;
    display: flex;
    align-items: center;
    justify-content: center;
    background: radial-gradient(circle at 30% 30%, #ffffff 0, #f0f0f0 40%, #d0d0d0 100%);
}

.logo-mark-inner {
    font-family: var(--font-heading);
    font-weight: var(--font-weight-bold);
    font-size: 16px;
    color: var(--color-primary-dark);
}

.wordmark-link {
    font-family: var(--font-script);
    font-size: 28px;
    font-weight: 400;
    color: var(--color-neutral-0);
    text-decoration: none;
    white-space: nowrap;
}

/* Main navigation */
.main-nav {
    flex: 1 1 auto;
}

.nav-list {
    display: flex;
    justify-content: center;
    align-items: stretch;
    list-style: none;
    padding: 0;
    margin: 0;
    gap: 0;
}

.nav-item {
    position: relative;
}

.nav-link {
    display: inline-block;
    padding: 0.75rem 1.5rem;
    color: var(--color-neutral-0);
    font-family: var(--font-heading);
    font-size: 14px;
    font-weight: var(--font-weight-medium);
    line-height: 1;
    text-decoration: none;
    white-space: nowrap;
}

.nav-link:hover,
.nav-link:focus {
    background-color: #1a1a1a;
    text-decoration: none;
}

/* Active nav item state (apply .is-active to the relevant link per page) */
.nav-link.is-active {
    background-color: var(--color-accent);
    color: var(--color-neutral-0);
}

/* Header tools: search icon + user menu */
.header-tools {
    display: flex;
    align-items: center;
    gap: var(--space-sm);
    flex-shrink: 0;
}

.header-search-icon {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    width: 32px;
    height: 32px;
    border-radius: 2px;
    background-color: #222222;
    font-size: 15px;
}

/* User menu */
.user-menu {
    position: relative;
}

.user-avatar {
    display: inline-flex;
    align-items: center;
    gap: 6px;
    padding: 4px 10px;
    border-radius: 2px;
    background-color: #222222;
    color: var(--color-neutral-0);
    font-size: 13px;
    text-decoration: none;
}

.user-avatar:hover,
.user-avatar:focus {
    background-color: #292929;
}

.user-initials {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    width: 24px;
    height: 24px;
    border-radius: 50%;
    background-color: var(--color-accent);
    font-size: 11px;
    font-weight: var(--font-weight-semibold);
}

.user-caret {
    font-size: 10px;
}

.user-dropdown {
    position: absolute;
    top: 100%;
    right: 0;
    margin-top: 4px;
    min-width: 200px;
    background-color: var(--color-neutral-0);
    border: 1px solid #e0e0e0;
    box-shadow: 0 2px 6px rgba(0, 0, 0, 0.15);
    list-style: none;
    padding: 4px 0;
    margin: 0;
    display: none;
    z-index: 20;
}

.user-dropdown li a {
    display: block;
    padding: 8px 14px;
    font-size: 13px;
    color: var(--color-neutral-900);
    text-decoration: none;
}

.user-dropdown li a:hover,
.user-dropdown li a:focus {
    background-color: #f3f3f3;
    color: var(--color-accent);
}

/* Show dropdown on hover/focus */
.user-menu:hover .user-dropdown,
.user-menu:focus-within .user-dropdown {
    display: block;
}

/* =========
   Main content
   ========= */
.site-main {
    flex: 1 0 auto;
    background-color: var(--color-neutral-0);
    padding-top: var(--space-xl);
    padding-bottom: var(--space-xxl);
}

/* Keep content centered like the reference layout */
#content {
    max-width: 960px;
    margin: 0 auto;
    padding: 0 var(--space-sm);
}

/* =========
   Footer
   ========= */
.site-footer {
    background-color: var(--color-primary-dark);
    color: #cccccc;
    border-top: 3px solid var(--color-accent);
    font-size: var(--font-size-small);
}

.footer-inner {
    padding-top: var(--space-lg);
    padding-bottom: var(--space-lg);
}

.footer-nav {
    margin-bottom: var(--space-md);
}

.footer-links {
    display: flex;
    flex-wrap: wrap;
    gap: var(--space-xs) var(--space-lg);
    list-style: none;
    padding: 0;
    margin: 0 0 var(--space-md) 0;
}

.footer-links a {
    color: #f0f0f0;
    text-decoration: none;
}

.footer-links a:hover,
.footer-links a:focus {
    text-decoration: underline;
    color: var(--color-accent);
}

.footer-meta {
    border-top: 1px solid #2a2a2a;
    padding-top: var(--space-sm);
}

.footer-organization {
    margin: 0 0 4px 0;
}

.footer-copy {
    margin: 0;
    color: #aaaaaa;
}

/* =========
   Typography helpers
   ========= */
.site-main h1,
.site-main h2,
.site-main h3,
.site-main h4 {
    font-family: var(--font-heading);
    font-weight: var(--font-weight-semibold);
    color: var(--color-neutral-900);
}

.site-main h1 {
    font-size: var(--font-size-h1);
    line-height: var(--line-height-tight);
}

.site-main h2 {
    font-size: var(--font-size-h2);
}

.site-main h3 {
    font-size: var(--font-size-h3);
}

.site-main p {
    margin-top: 0;
    margin-bottom: var(--space-sm);
}

/* =========
   Responsive adjustments
   ========= */
@media (max-width: 960px) {
    .header-inner {
        flex-wrap: wrap;
        height: auto;
        padding-top: var(--space-sm);
        padding-bottom: var(--space-sm);
        gap: var(--space-sm);
    }

    .branding {
        flex: 1 0 100%;
        margin-bottom: var(--space-xs);
    }

    .main-nav {
        order: 3;
        width: 100%;
    }

    .nav-list {
        justify-content: flex-start;
        flex-wrap: wrap;
    }

    .nav-link {
        padding: 0.5rem 1rem;
    }

    .header-tools {
        order: 2;
    }
}

@media (max-width: 640px) {
    .top-bar-inner {
        flex-direction: column;
        align-items: flex-start;
        justify-content: center;
        gap: 2px;
    }

    .site-main {
        padding-top: var(--space-lg);
        padding-bottom: var(--space-xl);
    }

    .footer-links {
        flex-direction: column;
        gap: 4px;
    }
}
